#include<bits/stdc++.h>
using namespace std;
int fail[1000010],son[1000010][31],cnt[1000010],ans[1000010],tot;
void insert(string s,int id)
{
    int p=0,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        if(!son[p][x])
        {
            son[p][x]=++tot;
        }
        p=son[p][x];
    }
    cnt[p]=id;
}
void getfail()
{
    queue<int> q;
    for(int i=0;i<26;i++)
    {
        if(son[0][i])
        {
            fail[son[0][i]]=0;
            q.push(son[0][i]);
        }
    }
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        for(int i=0;i<26;i++)
        {
            if(son[t][i])
            {
                fail[son[t][i]]=son[fail[t]][i];
                q.push(son[t][i]);
            }
            else
            {
                son[t][i]=son[fail[t]][i];
            }
        }
    }
}
void query(string s)
{
    int len=s.size();
    int p=0;
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        p=son[p][x];
        for(int t=p;t!=0;t=fail[t])
        {
            ans[cnt[t]]++;
        }
    }
}
string s[1000010];
int main()
{
    int n;
    while(scanf("%d",&n)==1&&n)
    {
        scanf("%d",&n);
        memset(son[0],0,sizeof(son[0]));
        tot=0;
        memset(ans,0,sizeof(ans));
        memset(cnt,0,sizeof(cnt));
        memset(fail,0,sizeof(fail));
        for(int i=1;i<=100000;i++)
        {
            memset(son[i],0,sizeof(son[i]));
        }
        for(int i=1;i<=n;i++)
        {
            cin>>s[i];
            insert(s[i],i);
        }
        string str;
        cin>>str;
        getfail();
        query(str);
        int max1=0;
        for(int i=1;i<=n;i++)
        {
            max1=max(max1,ans[i]);
        }
        printf("%d\n",max1);
        for(int i=1;i<=n;i++)
        {
            if(ans[i]==max1)
            {
                cout<<s[i]<<"\n";
            }
        }
    }
    return 0;
}
